mapper.select:
SELECT CART_SN, USER_ID, PROD_DIV_CD, PROD_SN, PROD_NM, PROD_PRICE, ITEM_QTY, REG_DT
FROM CART
WHERE USER_ID = #{userId}
  AND PROD_DIV_CD = #{prodDivCd}
  AND PROD_SN = #{prodSn}

mapper.delete:
DELETE FROM CART
WHERE USER_ID = #{userId}
  AND REG_DT < SYSDATE - 30

DELETE FROM CART
WHERE CART_SN = #{cartSn}
  AND USER_ID = #{userId}

DELETE FROM CART
WHERE USER_ID = #{userId}
  AND PROD_DIV_CD = #{prodDivCd}
  AND PROD_SN = #{prodSn}

mapper.update:
UPDATE CART
SET ITEM_QTY = #{itemQty}
WHERE CART_SN = #{cartSn}
  AND USER_ID = #{userId}
  AND PROD_DIV_CD = 'TEXTBOOK'
